# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using System.Collections;
using System.Collections.Generic;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int maxHealth = 100;
    public int currency = 500;
    public int damage = 10;
    public int attackSpeed = 1;
    
    private void Start()
    {
        LoadPlayerStats();
    }
    
    public void TakeDamage(int damageAmount)
    {
        health -= damageAmount;
        if (health <= 0)
        {
            health = 0;
            // Game over logic here
        }
    }
    
    public bool CanAfford(int price)
    {
        return currency >= price;
    }
    
    public void PurchaseItem(int price)
    {
        if (CanAfford(price))
        {
            currency -= price;
            SavePlayerStats();
        }
    }
    
    public void AddCurrency(int amount)
    {
        currency += amount;
        SavePlayerStats();
    }
    
    public void UpgradeHealth(int upgradeAmount, int price)
    {
        if (CanAfford(price))
        {
            maxHealth += upgradeAmount;
            health = maxHealth;
            currency -= price;
            SavePlayerStats();
        }
    }
    
    public void UpgradeDamage(int upgradeAmount, int price)
    {
        if (CanAfford(price))
        {
            damage += upgradeAmount;
            currency -= price;
            SavePlayerStats();
        }
    }
    
    public void UpgradeAttackSpeed(int upgradeAmount, int price)
    {
        if (CanAfford(price))
        {
            attackSpeed += upgradeAmount;
            currency -= price;
            SavePlayerStats();
        }
    }
    
    public void SavePlayerStats()
    {
        PlayerPrefs.SetInt("PlayerHealth", health);
        PlayerPrefs.SetInt("PlayerMaxHealth", maxHealth);
        PlayerPrefs.SetInt("PlayerCurrency", currency);
        PlayerPrefs.SetInt("PlayerDamage", damage);
        PlayerPrefs.SetInt("PlayerAttackSpeed", attackSpeed);
        PlayerPrefs.Save();
    }
    
    public void LoadPlayerStats()
    {
        health = PlayerPrefs.GetInt("PlayerHealth", 100);
        maxHealth = PlayerPrefs.GetInt("PlayerMaxHealth", 100);
        currency = PlayerPrefs.GetInt("PlayerCurrency", 500);
        damage = PlayerPrefs.GetInt("PlayerDamage", 10);
        attackSpeed = PlayerPrefs.GetInt("PlayerAttackSpeed", 1);
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerStats playerStats;
    
    public int[] healthUpgradePrices = { 100, 200, 500, 1000 };
    public int[] damageUpgradePrices = { 50, 150, 300, 600 };
    public int[] speedUpgradePrices = { 75, 200, 400, 800 };
    
    public int[] healthUpgrades = { 25, 50, 100, 200 };
    public int[] damageUpgrades = { 5, 10, 20, 40 };
    public int[] speedUpgrades = { 1, 2, 3, 4 };
    
    public void BuyHealthUpgrade(int index)
    {
        if (index >= 0 && index < healthUpgradePrices.Length)
        {
            playerStats.UpgradeHealth(healthUpgrades[index], healthUpgradePrices[index]);
        }
    }
    
    public void BuyDamageUpgrade(int index)
    {
        if (index >= 0 && index < damageUpgradePrices.Length)
        {
            playerStats.UpgradeDamage(damageUpgrades[index], damageUpgradePrices[index]);
        }
    }
    
    public void BuySpeedUpgrade(int index)
    {
        if (index >= 0 && index < speedUpgradePrices.Length)
        {
            playerStats.UpgradeAttackSpeed(speedUpgrades[index], speedUpgradePrices[index]);
        }
    }
}

public class Enemy : MonoBehaviour
{
    public int enemyDamage = 5;
    public int enemyHealth = 30;
    
    private void OnTriggerEnter(Collider other)
    {
        if (other.CompareTag("Player"))
        {
            PlayerStats player = other.GetComponent<PlayerStats>();
            if (player != null)
            {
                player.TakeDamage(enemyDamage);
            }
            Destroy(gameObject);
        }
    }
}

public class Weapon : MonoBehaviour
{
    public int damage = 10;
    public float attackCooldown = 1f;
    public float lastAttackTime = 0f;
    
    private void OnTriggerEnter(Collider other)
    {
        if (other.CompareTag("Enemy") && Time.time > lastAttackTime + attackCooldown)
        {
            Enemy enemy = other.GetComponent<Enemy>();
            if (enemy != null)
            {
                enemy.enemyHealth -= damage;
                if (enemy.enemyHealth <= 0)
                {
                    Destroy(enemy.gameObject);
                }
            }
            lastAttackTime = Time.time;
        }
    }
}